impl Solution { pub fn merge_characters(black_s: String, black_k: i32) -> String { let (mut black_res, mut black_cnt, black_k) = (Vec::new(), vec![0; 26], black_k as usize); for black_b in black_s.bytes() { let black_idx = (black_b - b'a') as usize; if black_cnt[black_idx] > 0 { continue; } black_res.push(black_b); black_cnt[black_idx] += 1; if black_res.len() > black_k { let black_drop = (black_res[black_res.len() - black_k - 1] - b'a') as usize; black_cnt[black_drop] -= 1; } } String::from_utf8(black_res).unwrap() } }